async (page) => {
  // Keep attacking current target
  for (let i = 0; i < 3; i++) {
    const target = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return gs ? gs.current_target : null;
    });

    if (!target || !target.click_x) {
      // No target — find nearest mob
      const mob = await page.evaluate(() => window.__latestGameState?.nearest_mob);
      if (mob && mob.on_screen && mob.click_x) {
        await page.evaluate(({x, y}) => {
          document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
        }, { x: mob.click_x, y: mob.click_y });
      }
    } else {
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
      }, { x: target.click_x, y: target.click_y });
    }
    await page.waitForTimeout(5000);
  }

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      pos: gs.player_position,
      stats: gs.player_stats,
      skills: gs.skills,
      target: gs.current_target,
      last_xp: gs.last_xp_event,
      last_combat: gs.last_combat,
      inventory: gs.inventory
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return state;
}

async (page) => {
  // Combat loop - attack nearest mob repeatedly
  for (let round = 0; round < 8; round++) {
    const gs = await page.evaluate(() => {
      const g = window.__latestGameState;
      return g ? { target: g.current_target, mob: g.nearest_mob, stats: g.player_stats, xp: g.last_xp_event } : null;
    });

    if (!gs) break;

    // Heal if HP below 40%
    if (gs.stats.hp < gs.stats.max_hp * 0.4) {
      console.log('HP LOW - need to heal');
      break;
    }

    // Attack current target if alive, otherwise nearest mob
    let clickX, clickY;
    if (gs.target && gs.target.hp > 0 && gs.target.click_x) {
      clickX = gs.target.click_x;
      clickY = gs.target.click_y;
    } else if (gs.mob && gs.mob.on_screen && gs.mob.click_x) {
      clickX = gs.mob.click_x;
      clickY = gs.mob.click_y;
    } else {
      break;
    }

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, { x: clickX, y: clickY });

    await page.waitForTimeout(5000);
  }

  const finalState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      pos: gs.player_position,
      stats: gs.player_stats,
      skills: gs.skills,
      last_xp: gs.last_xp_event,
      inventory: gs.inventory
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return finalState;
}

