async (page) => {
  // Find Oak trees in fresh state and click them immediately
  let totalLogs = 3;

  for (let attempt = 0; attempt < 10 && totalLogs < 10; attempt++) {
    // Get fresh entity list
    const entities = await page.evaluate(() => {
      const m = window.__latestAsciiMap;
      return m ? m.entities : null;
    });

    // Find nearest oak in entity map
    const oaks = entities ? Object.entries(entities).filter(([k, e]) => e.name === 'Oak') : [];
    oaks.sort((a, b) => a[1].distance - b[1].distance);

    if (oaks.length === 0) {
      await page.waitForTimeout(2000);
      continue;
    }

    const [label] = oaks[0];
    const result = await page.evaluate((lbl) => JSON.stringify(window.__clickEntity(lbl)), label);
    console.log('Chopping', label, ':', result);
    await page.waitForTimeout(4000);

    const inv = await page.evaluate(() => window.__latestGameState?.inventory);
    const logCount = inv ? inv.filter(i => i.key === 'logs').length : 0;
    totalLogs = logCount;
    console.log('Logs:', logCount, 'inv:', inv?.map(i => i.name + ':' + i.slot).join(', '));
  }

  const finalState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      pos: gs.player_position,
      stats: gs.player_stats,
      inventory: gs.inventory,
      quests: gs.quests?.filter(q => q.key === 'foresting')
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return finalState;
}

