async (page) => {
  let logsCount = 6;
  const clickedOaks = new Set();

  for (let round = 0; round < 20 && logsCount < 10; round++) {
    const oaks = await page.evaluate(() => {
      const gs = window.__latestGameState;
      if (!gs) return [];
      return gs.nearby_entities
        .filter(e => e.name === 'Oak' && e.on_screen && e.click_x)
        .sort((a, b) => a.distance - b.distance);
    });

    // Try to find an oak we haven't clicked recently
    let oak = oaks.find(o => !clickedOaks.has(o.id));
    if (!oak && oaks.length > 0) {
      // Reset if all clicked, try first one
      clickedOaks.clear();
      oak = oaks[0];
    }

    if (!oak) {
      // Walk to find more trees
      await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 225, y: 108});
      await page.waitForTimeout(3000);
      continue;
    }

    clickedOaks.add(oak.id);
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, { x: oak.click_x, y: oak.click_y });

    await page.waitForTimeout(4500);

    const inv = await page.evaluate(() => window.__latestGameState?.inventory);
    logsCount = inv ? inv.filter(i => i.key === 'logs').length : 0;
    console.log('Round', round, '| Logs:', logsCount, '| Clicked:', oak.id);
  }

  const finalState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({
      pos: gs.player_position,
      stats: gs.player_stats,
      inventory: gs.inventory,
      quests: gs.quests?.filter(q => q.key === 'foresting')
