async (page) => {
  let logsCount = 3;
  let noOakCount = 0;
  const searchPositions = [
    {x: 200, y: 120},
    {x: 205, y: 125},
    {x: 195, y: 130},
    {x: 210, y: 115},
    {x: 200, y: 110},
    {x: 215, y: 120},
    {x: 190, y: 115}
  ];
  let searchIdx = 0;

  for (let round = 0; round < 30 && logsCount < 10; round++) {
    const stats = await page.evaluate(() => window.__latestGameState?.player_stats);
    if (stats && stats.hp < stats.max_hp * 0.4) {
      // Eat blueberry or wait for regen
      const blueberry = await page.evaluate(() => {
        const gs = window.__latestGameState;
        return gs?.inventory?.find(i => i.key === 'blueberry');
      });
      if (blueberry) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), blueberry.slot);
        await page.waitForTimeout(1000);
      } else {
        await page.waitForTimeout(10000); // passive regen
      }
    }

    const oak = await page.evaluate(() => {
      const gs = window.__latestGameState;
      if (!gs) return null;
      return gs.nearby_entities.find(e => e.name === 'Oak' && e.on_screen && e.click_x) || null;
    });

    if (!oak) {
      noOakCount++;
      if (searchIdx < searchPositions.length) {
        await page.evaluate(({x, y}) => window.__clickTile(x, y), searchPositions[searchIdx % searchPositions.length]);
        searchIdx++;
        await page.waitForTimeout(3000);
