    await page.waitForTimeout(4500);

    const inv = await page.evaluate(() => window.__latestGameState?.inventory);
    logsCount = inv ? inv.filter(i => i.key === 'logs').length : 0;
    console.log('Round', round, '| Logs:', logsCount, '| Oak at:', oak.x, oak.y);
