      return gs?.nearest_mob?.on_screen && gs?.nearest_mob?.click_x ? gs.nearest_mob : null;
    });

    if (!mob) {
      await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 210, y: 120});
