    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, { x: mob.click_x, y: mob.click_y });
    await page.waitForTimeout(6000);

    const newStats = await page.evaluate(() => window.__latestGameState?.player_stats);
    console.log('Round', round, '| Level:', newStats?.level, '| HP:', newStats?.hp, '/', newStats?.max_hp, '| Kills:', kills);

    // Try check skills via UI
    const strength = await page.evaluate(() => {
      try {
        const p = window.game.player;
        // Try various paths
        if (p.skills && p.skills.strength) return p.skills.strength.level;
        if (p.skills && p.skills.Strength) return p.skills.Strength.level;
        return null;
      } catch(e) { return null; }
    });
    console.log('Strength level:', strength);

    kills++;
  }

  const finalState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return JSON.stringify({ pos: gs.player_position, stats: gs.player_stats, level: gs.player_stats?.level });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return finalState;
}

