async (page) => {
  // Click quest button to accept
  await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn) btn.click();
  });
  await page.waitForTimeout(1500);

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return s ? JSON.stringify({
      pos: s.player_position,
      quests: s.quests?.filter(q => q.key.includes('bike') || q.key.includes('lyson') || q.key.includes('rick')),
      nearby_achievements: s.nearby_entities?.filter(e => e.has_achievement)
    }) : 'NO_STATE';
  });

  return state;
}

async (page) => {
  const asciiMap = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    return m && !m.error ? (m.ascii + '\n\n' + m.legendText) : JSON.stringify(m);
  });
  return asciiMap;
}
